import React, { useEffect, useState } from "react";
import api from "../../api/axios";
import "../admin/Admin.css";
import "./Student.css";

export default function StudentSchedule() {
  const [enrollments, setEnrollments] = useState([]);
  const [schedules, setSchedules] = useState([]);
  const [classes, setClasses] = useState([]);
  const [courses, setCourses] = useState([]);
  const [filter, setFilter] = useState("all"); // all | week | month
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchAll = async () => {
      setLoading(true);
      try {
        const [eRes, cRes, courseRes] = await Promise.all([
          api.get("/student/enrollments"),
          api.get("/classes").catch(() => ({ data: { data: [] } })),
          api.get("/courses"),
        ]);
        const myEnrollments = (eRes.data.data || []).filter(e => ["approved","enrolled"].includes(e.status));
        setEnrollments(myEnrollments);
        setClasses(cRes.data.data || []);
        setCourses(courseRes.data.data || []);

        // Lấy schedules của các lớp đang học
        const myClassIds = myEnrollments.map(e => e.classId).filter(Boolean);
        const allSchedules = [];
        for (const classId of myClassIds) {
          const r = await api.get(`/schedules/class/${classId}`).catch(() => ({ data: { data: [] } }));
          allSchedules.push(...(r.data.data || []).map(s => ({ ...s, classId })));
        }
        setSchedules(allSchedules);
      } catch { }
      finally { setLoading(false); }
    };
    fetchAll();
  }, []);

  const getClass = (classId) => classes.find(c => c.id === classId || c.id === Number(classId));
  const getCourse = (courseId) => courses.find(c => c.id === courseId || c.id === Number(courseId));

  const now = new Date();
  const startOfWeek = new Date(now); startOfWeek.setDate(now.getDate() - now.getDay() + 1);
  const endOfWeek = new Date(startOfWeek); endOfWeek.setDate(startOfWeek.getDate() + 6);
  const startOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
  const endOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0);

  const filteredSchedules = schedules.filter(s => {
    const d = new Date(s.ngayHoc || s.date);
    if (filter === "week") return d >= startOfWeek && d <= endOfWeek;
    if (filter === "month") return d >= startOfMonth && d <= endOfMonth;
    return true;
  }).sort((a, b) => new Date(a.ngayHoc || a.date) - new Date(b.ngayHoc || b.date));

  const STATUS_BADGE = { scheduled: "badge-blue", ongoing: "badge-green", completed: "badge-gray", cancelled: "badge-red" };
  const STATUS_LABEL = { scheduled: "Đã lên lịch", ongoing: "Đang diễn ra", completed: "Hoàn thành", cancelled: "Đã hủy" };

  if (loading) return <div className="page-loading"><div className="spinner" /></div>;

  return (
    <div className="admin-page fade-in">
      <div className="page-header">
        <h1>Lớp & Lịch học</h1>
        <p>Thông tin lớp học và lịch học của bạn</p>
      </div>

      {/* My Classes */}
      <div className="section-card" style={{ marginBottom: 20 }}>
        <h3 className="section-title">🏫 Lớp đang tham gia</h3>
        {enrollments.length === 0
          ? <div className="empty-state"><p>Bạn chưa tham gia lớp học nào</p></div>
          : (
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(240px, 1fr))", gap: 12 }}>
              {enrollments.map(e => {
                const cls = getClass(e.classId);
                const course = getCourse(e.courseId);
                if (!cls) return null;
                return (
                  <div key={e.id} className="my-class-card">
                    <div className="my-class-header">
                      <span className={`badge ${course?.examType === "IELTS" ? "badge-blue" : "badge-green"}`}>
                        {course?.examType}
                      </span>
                      <h4>{cls.name}</h4>
                      <p>{course?.title}</p>
                    </div>
                    <div className="my-class-body">
                      <div className="my-class-info">
                        <span>📅 {cls.startDate ? new Date(cls.startDate).toLocaleDateString("vi-VN") : "—"}</span>
                        <span>→ {cls.endDate ? new Date(cls.endDate).toLocaleDateString("vi-VN") : "—"}</span>
                      </div>
                      <div style={{ marginTop: 8 }}>
                        <div style={{ display: "flex", justifyContent: "space-between", fontSize: "0.72rem", color: "var(--gray-500)", marginBottom: 4 }}>
                          <span>Tiến độ</span>
                          <span>{e.progress || 0}%</span>
                        </div>
                        <div style={{ height: 6, background: "var(--gray-100)", borderRadius: 3, overflow: "hidden" }}>
                          <div style={{ height: "100%", width: `${e.progress || 0}%`, background: "var(--primary)", borderRadius: 3 }} />
                        </div>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )
        }
      </div>

      {/* Schedules */}
      <div className="section-card">
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <h3 className="section-title" style={{ margin: 0 }}>📅 Lịch học</h3>
          <div className="teacher-tabs" style={{ margin: 0 }}>
            {["week","month","all"].map(f => (
              <button key={f} className={`ttab ${filter === f ? "active" : ""}`} onClick={() => setFilter(f)}>
                {f === "week" ? "Tuần này" : f === "month" ? "Tháng này" : "Tất cả"}
              </button>
            ))}
          </div>
        </div>

        {filteredSchedules.length === 0
          ? <div className="empty-state"><p>Không có lịch học nào</p></div>
          : filteredSchedules.map(s => {
            const cls = getClass(s.classId);
            const course = getCourse(cls?.courseId);
            const isToday = new Date(s.ngayHoc || s.date).toDateString() === now.toDateString();
            return (
              <div key={s.id} className={`schedule-item ${isToday ? "today" : ""}`}>
                <div className="schedule-date">
                  <span className="date-day">{new Date(s.ngayHoc || s.date).getDate()}</span>
                  <span className="date-month">{new Date(s.ngayHoc || s.date).toLocaleDateString("vi-VN", { month: "short" })}</span>
                  {isToday && <span className="today-dot" />}
                </div>
                <div className="schedule-content">
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                    <div>
                      <p style={{ fontWeight: 600 }}>{s.tieuDe || s.title}</p>
                      <p style={{ fontSize: "0.78rem", color: "var(--gray-500)", marginTop: 2 }}>
                        {cls?.name} · {course?.title}
                      </p>
                    </div>
                    <span className={`badge ${STATUS_BADGE[s.trangThai || s.status]}`}>
                      {STATUS_LABEL[s.trangThai || s.status]}
                    </span>
                  </div>
                  <div className="schedule-meta">
                    <span>⏰ {(s.gioBatDau || s.startTime)?.slice(0,5)} – {(s.gioKetThuc || s.endTime)?.slice(0,5)}</span>
                    {s.loaiLichHoc === "online" || s.type === "online"
                      ? <span>🌐 Trực tuyến {(s.linkOnline || s.link) && <a href={s.linkOnline || s.link} target="_blank" rel="noreferrer" style={{ color: "var(--primary)" }}>Tham gia</a>}</span>
                      : <span>📍 {s.diaDiem || s.location || "Tại trung tâm"}</span>}
                  </div>
                </div>
              </div>
            );
          })
        }
      </div>
    </div>
  );
}
